#include <stdio.h>
#include <stdlib.h>
#include <limits.h>

int cmp(const void *a, const void *b) {
    long long va = *(const long long *)a;
    long long vb = *(const long long *)b;
    return (va > vb) - (va < vb);
}

int main() {
    int T; if (scanf("%d", &T) != 1) return 0;
    while (T--) {
        int N; scanf("%d", &N);
        long long *C = (long long *)malloc(sizeof(long long) * 2 * N);
        for (int i = 0; i < N; ++i) scanf("%lld", &C[i]);
        for (int i = 0; i < N; ++i) scanf("%lld", &C[N + i]);
        qsort(C, 2 * N, sizeof(long long), cmp);
        long long ans = LLONG_MAX;
        for (int i = 0; i <= N; ++i) {
            long long diff = C[i + N - 1] - C[i];
            if (diff < ans) ans = diff;
        }
        printf("%lld\n", ans);
        free(C);
    }
    return 0;
}

