const fs = require('fs');
const data = fs.readFileSync(0, 'utf-8').trim().split(/\s+/);
let idx = 0;
function nextInt(){return Number(data[idx++]);}
const T = nextInt();
let out = [];
for(let t=0; t<T; ++t){
  const N = nextInt();
  const C = new Array(2*N);
  for(let i=0;i<N;++i) C[i]=nextInt();
  for(let i=0;i<N;++i) C[N+i]=nextInt();
  C.sort((a,b)=>a-b);
  let ans = Number.MAX_SAFE_INTEGER;
  for(let i=0;i<=N;++i){
    const diff = C[i+N-1] - C[i];
    if(diff < ans) ans = diff;
  }
  out.push(String(ans));
}
